const iniciar = () => {
  resetChat();
  return saludo();
};

const mensaje = (msg) => {
  let currentIntent = getCurrentIntent();
  if (!currentIntent) {
    return saludo();
  }
  switch (currentIntent) {
    case "saludo":
      return saludoRes(msg);
      break;
    case "authManejoDatos":
      return authManejoDatosRes(msg);
      break;
    case "mainOptions":
      return mainOptionsRes(msg);
      break;
    case "tomaMuestrasDom":
      return tomaMuestrasDomRes(msg);
      break;
    case "tomaMuestrasCovidDom":
      return tomaMuestrasCovidDomRes(msg);
      break;
    case "resultadosDom":
      return resultadosDomRes(msg);
      break;
    case "solicitudCitas":
      return solicitudCitasRes(msg);
      break;
    case "cancelarCitas":
      return cancelarCitasRes(msg);
      break;
    case "infoSedes":
      return infoSedesRes(msg);
      break;
    case "confirmacion":
      return confirmacionRes(msg);
      break;
    case "cancelar":
      return mainOptions(msg);
      break;
    default:
      return noEntendi();
      break;
  }
};

resetChat = () => {
  localStorage.removeItem("currentIntent");
  localStorage.removeItem("nameUser");
};
setCurrentIntent = (intent) => {
  localStorage.setItem("currentIntent", intent);
};

getCurrentIntent = () => {
  return localStorage.getItem("currentIntent");
};

setNameUser = (name) => {
  localStorage.setItem("nameUser", name);
};

getNameUser = () => {
  return localStorage.getItem("nameUser");
};

//Saludo del bot al usuario, y pide el nombre
saludo = () => {
  setCurrentIntent("saludo");

  return {
    message:
      "Hola, soy Angela, tu asistente virtual de Alianza Diagnóstica. ¿Cuál es tu nombre?",
  };
};

//Respuesta del usuario al saludo del bot, tomamos lo que escribió como el nombre
saludoRes = (nameUser) => {
  setNameUser(nameUser);
  return authManejoDatos();
};

//Muestra al usuario el mensaje para autorizar o no el tratamiento de datos
authManejoDatos = () => {
  setCurrentIntent("authManejoDatos");
  let user = getNameUser();
  return {
    message: `Hola, ${user}, es un placer que nos visites. ¿Aceptas el tratamiento de tus datos conforme a la política de privacidad consignada en esta página web?`,
    option: "mostrar_autorizacion_datos",
  };
};

//Recibimos la respuesta del usuario si acepta o no el tratamiento de datos
authManejoDatosRes = (rta) => {
  if (rta == "SI" || rta == "Si" || rta == "si") {
    return mainOptions();
  }
  if (rta == "NO" || rta == "No" || rta == "no") {
    return noManejoDatos();
  }
};

//Respuesta del bot si el usuario no acepta el tratamiento de datos
noManejoDatos = () => {
  setCurrentIntent("noManejoDatos");
  return {
    message:
      "De acuerdo, hemos borrado los datos que ingresaste, por lo tanto no puedo seguir ayudándote. Gracias por ponerte en contacto con nosotros. Te invitamos a seguir explorando nuestro sitio web.",
    option: "mostrar_rechaza_datos",
  };
};

//Mostrarle al usuario las opciones principales
mainOptions = () => {
  setCurrentIntent("mainOptions");
  let user = getNameUser();
  return {
    message: `${user}, ¿en qué te puedo ayudar?`,
    option: "mostrar_opciones_principales",
  };
};

//Respuesta del usuario a las opciones principales
mainOptionsRes = (rta) => {
  switch (rta) {
    case "ir_a_muestras":
      return tomaMuestrasDom();
      break;
    case "ir_a_muestras_covid":
      return tomaMuestrasCovidDom();
      break;
    case "ir_a_resultados":
      return resultadosDom();
      break;
    case "ir_a_citas":
      return solicitudCitas();
      break;
    case "ir_a_sedes":
      return infoSedes();
      break;
    case "ir_a_preparacion":
      return preparacionExamenes();
      break;
    case "ir_a_cancelar_citas":
      return cancelarCitas();
      break;
    case "ir_a_salir":
      return salir();
    default:
      return noEntendi();
      break;
  }
};

//Respuesta del bot para mostrar el formulario de toma de muestras a domicilio
tomaMuestrasDom = () => {
  setCurrentIntent("tomaMuestrasDom");
  let user = getNameUser();
  return {
    message: `${user}, para toma de muestras a domicilio diligencie el siguiente formulario:`,
    option: "mostrar_formulario_muestras",
  };
};

//Respuesta del usuario al enviar el formulario de toma de muestras a domicilio
tomaMuestrasDomRes = (rta) => {
  if (rta == "email_enviado") {
    return confirmacion();
  }
  if (rta == "ir_a_opciones_principales") {
    return mainOptions();
  }
  return noEntendi();
};

