//Respuesta del bot para mostrar el listado de las sedes
infoSedes = () => {
  setCurrentIntent("infoSedes");
  return {
    message: `Estas son nuestras sedes. Selecciona una para ver dirección, horarios y servicios prestados:`,
    option: "mostrar_opcion_sedes",
  };
};

//Respuesta del usuario a la opción de mostrar sedes, si quiere ir al menu principal o consultar otra sede
infoSedesRes = (rta) => {
  if (rta == "ir_a_opciones_principales") {
    return mainOptions();
  }
  if (rta == "ir_a_otra_sede") {
    return infoSedes();
  }
};

//Respuesta del bot para mostrar al usuario la opcion de preparación para exámenes
preparacionExamenes = () => {
  setCurrentIntent("preparacionExamenes");
  return {
    message: `link preparacion de examenes`,
  };
};

//Respuesta del bot al recibir los datos enviados por los formularios para muestras, resultados y citas
confirmacion = () => {
  setCurrentIntent("confirmacion");
  let user = getNameUser();
  return {
    message: `${user}, su solicitud fue recibida. Uno de nuestros agentes se pondrá en contacto lo más pronto posible. Le puedo colaborar en algo más?`,
    option: "mostrar_opcion_salir",
  };
};

//Respuesta del bot al recibir los datos enviados por los formularios para muestras, resultados y citas
confirmacionRes = (rta) => {
  if (rta == "ir_a_opciones_principales") {
    return mainOptions();
  }
  if (rta == "ir_a_salir") {
    return salir();
  }
};

//Respuesta del bot al solicitar salir de la conversación
salir = () => {
  resetChat();
  return {
    message: "Gracias por utilizar nuestros servicios.",
    option: "mostrar_volver_empezar",
  };
};

//Respuesta del bot cuando ninguna respuesta por parte del usuario se ha entendido
noEntendi = () => {
  return {
    message: "No entendí lo que dijiste.",
  };
};

exports.mensaje = mensaje;
exports.iniciar = iniciar;
